import axios from 'axios';
import toast from 'react-hot-toast';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Request interceptor to add auth token
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor to handle errors and token refresh
api.interceptors.response.use(
  (response) => {
    return response;
  },
  async (error) => {
    const originalRequest = error.config;

    if (error.response?.status === 401 && !originalRequest._retry) {
      originalRequest._retry = true;

      try {
        const refreshToken = localStorage.getItem('refreshToken');
        if (!refreshToken) {
          throw new Error('No refresh token');
        }

        const response = await axios.post(`${API_BASE_URL}/api/token/refresh/`, {
          refresh: refreshToken,
        });

        const { access } = response.data;
        localStorage.setItem('token', access);

        originalRequest.headers.Authorization = `Bearer ${access}`;
        return api(originalRequest);
      } catch (refreshError) {
        localStorage.removeItem('token');
        localStorage.removeItem('refreshToken');
        window.location.href = '/login';
        return Promise.reject(refreshError);
      }
    }

    return Promise.reject(error);
  }
);

// API endpoints
export const authAPI = {
  login: (credentials) => api.post('/api/login/', credentials),
  register: (userData) => api.post('/api/register/', userData),
  logout: () => api.post('/api/logout/'),
  refreshToken: (refresh) => api.post('/api/token/refresh/', { refresh }),
  getProfile: () => api.get('/api/profile/'),
  updateProfile: (data) => api.patch('/api/profile/', data),
  changePassword: (data) => api.post('/api/change-password/', data),
  becomeCreator: () => api.post('/api/become-creator/'),
  getCreatorProfile: () => api.get('/api/creator-profile/'),
  updateCreatorProfile: (data) => api.patch('/api/creator-profile/', data),
  uploadAvatar: (file) => {
    const formData = new FormData();
    formData.append('avatar', file);
    return api.post('/api/upload-avatar/', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    });
  },
  uploadCover: (file) => {
    const formData = new FormData();
    formData.append('cover_image', file);
    return api.post('/api/upload-cover/', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    });
  },
};

export const verificationAPI = {
  submitVerification: (data) => {
    const formData = new FormData();
    Object.keys(data).forEach(key => {
      formData.append(key, data[key]);
    });
    return api.post('/api/verification/request/', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    });
  },
  getVerificationStatus: () => api.get('/api/verification/status/'),
};

export const contentAPI = {
  getVideos: (params) => api.get('/api/videos/', { params }),
  getVideo: (id) => api.get(`/api/videos/${id}/`),
  uploadVideo: (data) => {
    const formData = new FormData();
    Object.keys(data).forEach(key => {
      if (data[key] !== null && data[key] !== undefined) {
        formData.append(key, data[key]);
      }
    });
    return api.post('/api/videos/', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    });
  },
  updateVideo: (id, data) => api.patch(`/api/videos/${id}/`, data),
  deleteVideo: (id) => api.delete(`/api/videos/${id}/`),
  likeVideo: (id, value) => api.post(`/api/videos/${id}/like/`, { value }),
  unlikeVideo: (id) => api.delete(`/api/videos/${id}/like/`),
  getComments: (videoId) => api.get(`/api/videos/${videoId}/comments/`),
  addComment: (videoId, data) => api.post(`/api/videos/${videoId}/comments/`, data),
  likeComment: (commentId, value) => api.post(`/api/comments/${commentId}/like/`, { value }),
  unlikeComment: (commentId) => api.delete(`/api/comments/${commentId}/like/`),
  reportVideo: (id, data) => api.post(`/api/videos/${id}/report/`, data),
  shareVideo: (id, data) => api.post(`/api/videos/${id}/share/`, data),
  downloadVideo: (id) => api.get(`/api/videos/${id}/download/`),
};

export const searchAPI = {
  search: (query, params) => api.get('/api/search/', { params: { q: query, ...params } }),
  getCategories: () => api.get('/api/categories/'),
  getTags: () => api.get('/api/tags/'),
  getTrending: () => api.get('/api/videos/trending/'),
  getRecommended: () => api.get('/api/videos/recommended/'),
};

export const subscriptionAPI = {
  getSubscriptions: () => api.get('/api/subscriptions/'),
  subscribe: (creatorId, data) => api.post(`/api/subscriptions/${creatorId}/`, data),
  unsubscribe: (creatorId) => api.delete(`/api/subscriptions/${creatorId}/`),
  getSubscribers: () => api.get('/api/subscribers/'),
};

export const paymentAPI = {
  getPaymentMethods: () => api.get('/api/payment-methods/'),
  addPaymentMethod: (data) => api.post('/api/payment-methods/', data),
  removePaymentMethod: (id) => api.delete(`/api/payment-methods/${id}/`),
  getPayoutMethods: () => api.get('/api/payout-methods/'),
  addPayoutMethod: (data) => api.post('/api/payout-methods/', data),
  removePayoutMethod: (id) => api.delete(`/api/payout-methods/${id}/`),
  getEarnings: (params) => api.get('/api/earnings/', { params }),
  requestPayout: (data) => api.post('/api/payouts/', data),
  getPayouts: () => api.get('/api/payouts/'),
  tipCreator: (creatorId, data) => api.post(`/api/tips/${creatorId}/`, data),
  purchaseVideo: (videoId, data) => api.post(`/api/videos/${videoId}/purchase/`, data),
};

export const analyticsAPI = {
  getStats: () => api.get('/api/stats/'),
  getVideoStats: (videoId) => api.get(`/api/videos/${videoId}/stats/`),
  getCreatorStats: (creatorId) => api.get(`/api/creators/${creatorId}/stats/`),
};

export default api;
